{
  "narrative": "你蹲在青茅山腰的老槐树下，审视那条被荒草半掩的旧山路。月光稀薄，碎石路段偶见新鲜爪印——是山猫还是别的什么？猎户老王曾提过这条路能抄近道前往南疆关口，但近年少有人走，或许有塌方或埋伏。你掂了掂腰间的水囊，确认火折子干燥。",
  "world_action_candidates": [
    "点燃火把，沿旧山路摸黑前行",
    "退回山脚村落，向猎人换条更稳妥的路线",
    "就地扎营，待天亮再探路况"
  ],
  "rumors": [
    "旧山路中段曾有一支商队失踪，至今未找到尸骨",
    "南疆巡边队最近加强了夜间盘查，走小路可能更安全"
  ],
  "pressure": [
    "干粮只够两日，必须在日落前抵达南疆边缘",
    "身上的旧伤隐隐作痛，拖延只会更糟"
  ],
  "safety_notes": [
    "旧山路夜间视线差，建议携带照明物和防身短兵",
    "若遇无法通过的塌方，可沿溪谷绕行，但要多费半日"
  ]
}

{
  "narrative": "你察觉到一名低阶散修正潜伏在远处山脊上，目光阴冷地注视着你。南疆的湿热空气中弥漫着若有若无的杀意，林间异兽的低吼隐约可闻，仿佛在警告你已踏入危险之地。前方的路径蜿蜒曲折，商家城的轮廓仍被迷雾遮掩，但暗中的监视让你每一步都如芒在背。",
  "world_action_candidates": [
    "假装未察觉，暗中观察散修的动向",
    "主动靠近山脊，尝试与散修交涉",
    "避开监视，绕道而行"
  ],
  "rumors": [
    "据说有低阶散修在青茅山外缘劫掠落单修士",
    "商家城最近加强了外围巡逻，但仍有亡命之徒潜入"
  ],
  "pressure": [
    "散修的视线如针扎般令你难以集中精神",
    "空气中的异香越来越浓，可能混有迷魂毒雾"
  ],
  "safety_notes": [
    "保持警惕，避免暴露自己的底牌",
    "注意周围是否有埋伏或陷阱"
  ]
}

{
  "narrative": "你环顾四周，南疆外缘只有荒山野林，根本不见市场踪影。远处散修的杀意未消，空气中异香更浓，让你不敢贸然摆摊交易。往前或许有临时落脚点，但眼下必须优先应对暗中的监视。",
  "world_action_candidates": [
    "假装未察觉，暗中观察散修动向",
    "主动靠近山脊，尝试与散修交涉",
    "绕道寻找隐蔽处，先避开监视"
  ],
  "rumors": [
    "南疆外缘常有散修劫杀独行者",
    "湿热密林中可能藏有荒野草药商"
  ],
  "pressure": [
    "散修视线如针扎般令你难以集中精神",
    "空气中异香越来越浓，可能混有迷魂毒雾"
  ],
  "safety_notes": [
    "此区域无正式市场，禁止交易与兑换",
    "避免暴露贵重物品，防范隐藏因果"
  ]
}

{
  "narrative": "你走在青茅山出口的小径上，夕阳将树影拉长。前方隐约有灯火闪烁，传闻那就是南疆商家的方向。但你还未抵达商家城，脚下的路依然崎岖。山风带来远处的人声，却看不清虚实。你的行囊里干粮已不多，必须谨慎前行。",
  "world_action_candidates": [
    "继续沿着山径前进",
    "寻找安全的过夜地点",
    "侦察前方的灯火动静"
  ],
  "rumors": [
    "有商队说商家城还远在三天路程之外。",
    "路上可能遇到游荡的野兽或迷途的修士。"
  ],
  "pressure": [
    "山路陡峭，体力消耗加快。",
    "干粮和饮水需要计划使用。"
  ],
  "safety_notes": [
    "你尚未抵达商家城，无法加入势力或获得奖励。",
    "引擎控制正式位置变化，当前状态为青茅山出口路径。"
  ]
}

{
  "narrative": "你提及的姓名与仙蛊涉及本不该在此显现的隐秘因果。山径上并无任何凭证可证明那些传闻，只有风声与落叶。继续前行，留意脚下。",
  "world_action_candidates": [
    "沿山径继续前行",
    "寻找避风处休整"
  ],
  "rumors": [
    "有传说古老因果沉睡在南疆深处，但无人能证实。",
    "山野间偶有修士提及春秋轮回，不过是模糊呓语。"
  ],
  "pressure": [
    "山风渐冷，体感消耗加剧。",
    "干粮与饮水需精打细算。"
  ],
  "safety_notes": [
    "不要在此地深究无名禁忌。",
    "前方才是可安歇的商家势力范围。"
  ]
}

{
  "narrative": "山风萧瑟，你提到宝黄天与仙材之事，但此地只是凡人山径，并无任何仙家踪迹。路边偶遇一队行商，所售不过粗粮与草药，并无稀罕物。你或许能在此补充些干粮，或是加快脚步，寻前方村落歇脚。",
  "world_action_candidates": [
    "向行商购买干粮与水",
    "打听前方村落的详情",
    "继续沿山径赶路"
  ],
  "rumors": [
    "商队提到南疆深处有仙门传闻，但路途遥远"
  ],
  "pressure": [
    "寒风加剧，体力消耗加快",
    "干粮所剩不多，需及时补充"
  ],
  "safety_notes": [
    "保持凡人定位，勿涉仙材交易",
    "任何宝黄天提及均降级为远方传说"
  ]
}
